#include <iostream>
#include <algorithm>
using namespace std;
int gcd(int a,int b)
{
    int yu;
    if(a<b)
    {
        swap(a,b);
    }
    while(a%b!=0)
    {
        yu=a%b;
        a=b;
        b=yu;
    }
    return b;
}
int main()
{
    int x,y,p,q,count=0;
    cin>>x>>y;
    for(p=x;p<=y;p++)
    {
        q=x*y/p;
        int yin=gcd(p,q),bei;
        bei=p*q/yin;
        if(yin==x&&bei==y)
        {
            count++;
        }
    }
    cout<<count;
    return 0;
}
